const getRevokeCashChainName = (chainId: number): string | null => {
  const chainMap: Record<number, string> = {
    1: 'ethereum',
    8453: 'base',
    42161: 'arbitrum',
    137: 'polygon',
    10: 'optimism',
    56: 'bsc',
    43114: 'avalanche',
    59144: 'linea',
    534352: 'scroll',
    5000: 'mantle',
    324: 'zksync',
    250: 'fantom',
    100: 'gnosis',
    42220: 'celo',
  }
  return chainMap[chainId] || null
}

